      { icone: "🥬", titre: "Légumes d'été", detail: "Ajouter au bouillon : courgettes en cubes, tomates pelées et concassées, pommes de terre, haricots verts coupés. Cuire 15 min.", badge: "⏱ 15 min" },
      { icone: "🍝", titre: "Pâtes", detail: "Ajouter les petites pâtes (coquillettes ou langues d'oiseau). Cuire 8-10 min.", badge: "⏱ 10 min" },
      { icone: "🌿", titre: "Le pistou", detail: "Pendant ce temps : piler au mortier ail et basilic frais (PAS de mixeur, ça oxyde). Ajouter parmesan râpé et huile d'olive en filet en montant comme une mayonnaise.", badge: "⏱ 10 min" },
      { icone: "🥄", titre: "Assembler", detail: "Hors du feu, incorporer 2/3 du pistou à la soupe. Servir avec le reste du pistou à part. ASTUCE CHEF : ne jamais cuire le pistou, ça tue les arômes.", badge: null },
      { icone: "🧀", titre: "Servir", detail: "Présenter avec un pot de pistou et du parmesan râpé pour que chacun se serve. Le pain frotté à l'ail complète parfaitement.", badge: null }
