      { icone: "🦐", titre: "Préparer les crevettes", detail: "Décortiquer 200g de crevettes crues. Les hacher GROSSIÈREMENT au couteau (pas en purée). ASTUCE CHEF : conserver une certaine texture pour la garniture.", badge: "⏱ 8 min" },
      { icone: "🥩", titre: "Farce wonton", detail: "Mélanger : porc haché (200g) + crevettes hachées + 1 cc d'huile de sésame + 1 cc de sauce soja + gingembre râpé (1 cc) + ciboule émincée (2) + 1 cc de fécule + 1 pincée de sel + poivre blanc. Mélanger ENERGIQUEMENT 2 min : la farce doit devenir COLLANTE (= bonne tenue).", badge: "⏱ 5 min" },
      { icone: "🥟", titre: "Plier les wontons", detail: "TECHNIQUE PRO : sur chaque feuille de wonton (20 feuilles), déposer 1/2 cc de farce au centre. Mouiller les bords avec un peu d'eau. Plier en TRIANGLE, presser fortement. Puis rabattre les 2 pointes inférieures vers l'avant en les pinçant ensemble. Forme caractéristique du 'lingot d'or'.", badge: "⏱ 20 min" },
      { icone: "❄️", titre: "Réserver", detail: "Disposer les wontons sur une plaque farinée SANS qu'ils se touchent (sinon ils collent). Filmer.", badge: null },
      { icone: "🍲", titre: "Bouillon parfumé", detail: "Dans une grande casserole : 1L de bouillon de poulet de QUALITÉ + 3 tranches de gingembre + 2 ciboules + 2 cc de sauce soja + 1 cc d'huile de sésame. Porter à frémissement, infuser 10 min.", badge: "⏱ 10 min" },
      { icone: "💧", titre: "Cuire les wontons", detail: "ASTUCE CHINOISE : porter 2L d'eau (À PART du bouillon) à frémissement. Y plonger les wontons. Ils sont cuits quand ils REMONTENT à la surface (3-4 min) + 1 min supplémentaire.", badge: "⏱ 5 min" },
      { icone: "🥢", titre: "Filtrer", detail: "Récupérer les wontons à l'écumoire. Cuisson séparée du bouillon = bouillon reste CLAIR (pas trouble par la fécule des pâtes).", badge: "⏱ 2 min" },
      { icone: "🍜", titre: "Dressage", detail: "Bol creux : disposer 5-6 wontons cuits par personne. Verser le bouillon brûlant par-dessus. Ajouter quelques pak choï blanchis si désiré.", badge: "⏱ 3 min" },
      { icone: "🌿", titre: "Garnitures", detail: "Parsemer de ciboule verte ciselée, coriandre fraîche, un filet d'huile de sésame, quelques gouttes de vinaigre noir chinois (option), piment frais ou huile pimentée pour ceux qui aiment.", badge: null },
      { icone: "🍽️", titre: "Service", detail: "Servir BRÛLANT. À déguster à la cuillère (bouillon) et baguettes (wontons). Le wonton se mange en UNE BOUCHÉE. Réconfort total !", badge: null }
